                 .Include(i => i.OfficeAssignment)
                 .Include(i => i.CourseAssignments)
                     .ThenInclude(c => c.Course)
                 .Where(i => i.ID == id)
                 .Single();
             PopulateAssignedCourseData(instructor);
             if (instructor == null)
             {
                 return NotFound();
             }
             return View(instructor);
