using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;

namespace ContosoUniversity.Tests.Helpers
{
    public static class TestHelpers
    {
        public static SchoolContext CreateContext(string? dbName = null)
        {
            dbName ??= Guid.NewGuid().ToString();
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName)
                .Options;
            return new SchoolContext(options);
        }

        public static void SeedStudents(SchoolContext context)
        {
            context.Students.AddRange(
                new Student { FirstMidName = "Alice", LastName = "Anderson", EnrollmentDate = new DateTime(2020, 9, 1) },
                new Student { FirstMidName = "Bob", LastName = "Brown", EnrollmentDate = new DateTime(2021, 9, 1) },
                new Student { FirstMidName = "Charlie", LastName = "Clark", EnrollmentDate = new DateTime(2022, 1, 15) }
            );
            context.SaveChanges();
        }

        public static void SeedInstructors(SchoolContext context)
        {
            context.Instructors.AddRange(
                new Instructor { FirstMidName = "Kim", LastName = "Abercrombie", HireDate = new DateTime(1995, 3, 11), CourseAssignments = new List<CourseAssignment>() },
                new Instructor { FirstMidName = "Fadi", LastName = "Fakhouri", HireDate = new DateTime(2002, 7, 6), CourseAssignments = new List<CourseAssignment>() }
            );
            context.SaveChanges();
        }

        public static void SeedDepartments(SchoolContext context)
        {
            SeedInstructors(context);
            var instructor = context.Instructors.First(i => i.LastName == "Abercrombie");
            context.Departments.AddRange(
                new Department { Name = "English", Budget = 350000, StartDate = new DateTime(2007, 9, 1), InstructorID = instructor.ID },
                new Department { Name = "Mathematics", Budget = 100000, StartDate = new DateTime(2007, 9, 1) }
            );
            context.SaveChanges();
        }

        public static void SeedCourses(SchoolContext context)
        {
            SeedDepartments(context);
            var dept = context.Departments.First(d => d.Name == "English");
            context.Courses.AddRange(
                new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = dept.DepartmentID },
                new Course { CourseID = 2021, Title = "Composition", Credits = 3, DepartmentID = dept.DepartmentID }
            );
            context.SaveChanges();
        }

        public static void SeedFullData(SchoolContext context)
        {
            SeedCourses(context);
            SeedStudents(context);

            var student = context.Students.First();
            var course = context.Courses.First();
            context.Enrollments.Add(new Enrollment
            {
                StudentID = student.ID,
                CourseID = course.CourseID,
                Grade = Grade.A
            });
            context.SaveChanges();
        }
    }
}

