using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly InstructorsController _controller;

        public InstructorsControllerTests()
        {
            _context = TestHelpers.CreateContext();
            _controller = new InstructorsController(_context);
            _controller.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        // --- Index ---

        [Fact]
        public void Index_NoSelection_ReturnsViewWithInstructors()
        {
            SeedInstructorsWithCourses();

            var result = _controller.Index(null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Models.SchoolViewModels.InstructorIndexData>(result!.Model);
            Assert.Equal(2, model.Instructors.Count());
        }

        [Fact]
        public void Index_WithInstructorId_PopulatesCourses()
        {
            SeedInstructorsWithCourses();
            var instructor = _context.Instructors.First();

            var result = _controller.Index(instructor.ID, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Models.SchoolViewModels.InstructorIndexData>(result!.Model);
            Assert.NotNull(model.Courses);
        }

        // --- Details ---

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsView()
        {
            TestHelpers.SeedInstructors(_context);
            var instructor = _context.Instructors.First();

            var result = _controller.Details(instructor.ID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result!.Model);
            Assert.Equal(instructor.ID, model.ID);
        }

        [Fact]
        public void Details_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Details(999);

            Assert.IsType<NotFoundResult>(result);
        }

        // --- Create GET ---

        [Fact]
        public void Create_Get_ReturnsViewWithInstructor()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result!.Model);
            Assert.NotNull(model.CourseAssignments);
        }

        // --- Create POST ---

        [Fact]
        public void Create_Post_ValidInstructor_RedirectsToIndex()
        {
            var instructor = new Instructor
            {
                FirstMidName = "Test",
                LastName = "Instructor",
                HireDate = new DateTime(2020, 1, 1),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _controller.Create(instructor, null!);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            Assert.True(_context.Instructors.Any(i => i.LastName == "Instructor"));
        }

        [Fact]
        public void Create_Post_WithSelectedCourses_AddsCourseAssignments()
        {
            TestHelpers.SeedCourses(_context);
            var courseIds = _context.Courses.Select(c => c.CourseID.ToString()).ToArray();

            var instructor = new Instructor
            {
                FirstMidName = "Test",
                LastName = "WithCourses",
                HireDate = new DateTime(2020, 1, 1),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _controller.Create(instructor, courseIds);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            var instructor = new Instructor
            {
                FirstMidName = "Test",
                LastName = "Instructor",
                HireDate = new DateTime(2020, 1, 1),
                CourseAssignments = new List<CourseAssignment>()
            };
            _controller.ModelState.AddModelError("LastName", "Error");

            var result = _controller.Create(instructor, null!) as ViewResult;

            Assert.NotNull(result);
        }

        // --- Edit GET ---

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsView()
        {
            SeedInstructorsWithCourses();
            var instructor = _context.Instructors.First();

            var result = _controller.Edit(instructor.ID) as ViewResult;

            Assert.NotNull(result);
            Assert.IsType<Instructor>(result!.Model);
        }

        // --- Delete GET ---

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsView()
        {
            TestHelpers.SeedInstructors(_context);
            var instructor = _context.Instructors.First();

            var result = _controller.Delete(instructor.ID) as ViewResult;

            Assert.NotNull(result);
            Assert.IsType<Instructor>(result!.Model);
        }

        [Fact]
        public void Delete_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(999);

            Assert.IsType<NotFoundResult>(result);
        }

        // --- DeleteConfirmed ---

        [Fact]
        public void DeleteConfirmed_RemovesInstructorAndRedirects()
        {
            SeedInstructorsWithCourses();
            var instructor = _context.Instructors.Include(i => i.OfficeAssignment).First();
            var initialCount = _context.Instructors.Count();

            var result = _controller.DeleteConfirmed(instructor.ID);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            Assert.Equal(initialCount - 1, _context.Instructors.Count());
        }

        [Fact]
        public void DeleteConfirmed_ClearsDepartmentAdministrator()
        {
            TestHelpers.SeedDepartments(_context);
            var instructor = _context.Instructors.First();
            var dept = _context.Departments.First(d => d.InstructorID == instructor.ID);

            // Ensure the instructor has CourseAssignments and OfficeAssignment loaded
            instructor.CourseAssignments ??= new List<CourseAssignment>();
            _context.OfficeAssignments.Add(new OfficeAssignment { InstructorID = instructor.ID, Location = "Room 1" });
            _context.SaveChanges();

            _controller.DeleteConfirmed(instructor.ID);

            var updatedDept = _context.Departments.Find(dept.DepartmentID);
            Assert.Null(updatedDept!.InstructorID);
        }

        private void SeedInstructorsWithCourses()
        {
            TestHelpers.SeedCourses(_context);
            var instructor = _context.Instructors.First();
            var course = _context.Courses.First();

            if (!_context.CourseAssignments.Any(ca => ca.InstructorID == instructor.ID && ca.CourseID == course.CourseID))
            {
                _context.CourseAssignments.Add(new CourseAssignment
                {
                    InstructorID = instructor.ID,
                    CourseID = course.CourseID
                });
                _context.SaveChanges();
            }
        }
    }
}

