+
+        [Fact]
+        public void SendNotification_MultipleNotifications_AllRetrievable()
+        {
+            for (int i = 0; i < 5; i++)
+            {
+                _service.SendNotification("Entity", i.ToString(), EntityOperation.CREATE);
+            }
+
+            var received = new List<Notification>();
+            Notification? n;
+            while ((n = _service.ReceiveNotification()) != null)
+            {
+                received.Add(n);
+            }
+
+            Assert.Equal(5, received.Count);
