using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Data
{
    public class SchoolContextTests : IDisposable
    {
        private readonly SchoolContext _context;

        public SchoolContextTests()
        {
            _context = TestHelpers.CreateContext();
        }

        public void Dispose()
        {
            _context.Dispose();
        }

        [Fact]
        public void CanAddAndRetrieveStudent()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = new DateTime(2023, 1, 1)
            };

            _context.Students.Add(student);
            _context.SaveChanges();

            var retrieved = _context.Students.Find(student.ID);
            Assert.NotNull(retrieved);
            Assert.Equal("Test", retrieved!.FirstMidName);
        }

        [Fact]
        public void CanAddAndRetrieveInstructor()
        {
            var instructor = new Instructor
            {
                FirstMidName = "Jane",
                LastName = "Doe",
                HireDate = new DateTime(2020, 1, 1),
                CourseAssignments = new List<CourseAssignment>()
            };

            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            var retrieved = _context.Instructors.Find(instructor.ID);
            Assert.NotNull(retrieved);
            Assert.Equal("Jane", retrieved!.FirstMidName);
        }

        [Fact]
        public void CanAddAndRetrieveCourse()
        {
            TestHelpers.SeedDepartments(_context);
            var dept = _context.Departments.First();

            var course = new Course
            {
                CourseID = 9999,
                Title = "Test Course",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };

            _context.Courses.Add(course);
            _context.SaveChanges();

            var retrieved = _context.Courses.Find(9999);
            Assert.NotNull(retrieved);
            Assert.Equal("Test Course", retrieved!.Title);
        }

        [Fact]
        public void CanAddAndRetrieveDepartment()
        {
            var department = new Department
            {
                Name = "Science",
                Budget = 250000,
                StartDate = new DateTime(2020, 9, 1)
            };

            _context.Departments.Add(department);
            _context.SaveChanges();

            var retrieved = _context.Departments.Find(department.DepartmentID);
            Assert.NotNull(retrieved);
            Assert.Equal("Science", retrieved!.Name);
        }

        [Fact]
        public void CanAddAndRetrieveEnrollment()
        {
            TestHelpers.SeedCourses(_context);
            TestHelpers.SeedStudents(_context);
            var student = _context.Students.First();
            var course = _context.Courses.First();

            var enrollment = new Enrollment
            {
                StudentID = student.ID,
                CourseID = course.CourseID,
                Grade = Grade.B
            };

            _context.Enrollments.Add(enrollment);
            _context.SaveChanges();

            var retrieved = _context.Enrollments.First(e => e.StudentID == student.ID && e.CourseID == course.CourseID);
            Assert.NotNull(retrieved);
            Assert.Equal(Grade.B, retrieved.Grade);
        }

        [Fact]
        public void CourseAssignment_HasCompositeKey()
        {
            TestHelpers.SeedCourses(_context);
            var instructor = _context.Instructors.First();
            var course = _context.Courses.First();

            var assignment = new CourseAssignment
            {
                InstructorID = instructor.ID,
                CourseID = course.CourseID
            };

            _context.CourseAssignments.Add(assignment);
            _context.SaveChanges();

            var retrieved = _context.CourseAssignments
                .Find(course.CourseID, instructor.ID);
            Assert.NotNull(retrieved);
        }

        [Fact]
        public void OfficeAssignment_LinkedToInstructor()
        {
            TestHelpers.SeedInstructors(_context);
            var instructor = _context.Instructors.First();

            var office = new OfficeAssignment
            {
                InstructorID = instructor.ID,
                Location = "Room 301"
            };

            _context.OfficeAssignments.Add(office);
            _context.SaveChanges();

            var retrieved = _context.OfficeAssignments.Find(instructor.ID);
            Assert.NotNull(retrieved);
            Assert.Equal("Room 301", retrieved!.Location);
        }

        [Fact]
        public void Student_FullName_ReturnsLastCommaFirst()
        {
            var student = new Student { FirstMidName = "Alice", LastName = "Smith" };

            Assert.Equal("Smith, Alice", student.FullName);
        }

        [Fact]
        public void Instructor_FullName_ReturnsLastCommaFirst()
        {
            var instructor = new Instructor { FirstMidName = "Bob", LastName = "Jones" };

            Assert.Equal("Jones, Bob", instructor.FullName);
        }

        [Fact]
        public void CanAddAndRetrieveNotification()
        {
            var notification = new Notification
            {
                EntityType = "Student",
                EntityId = "1",
                Operation = "CREATE",
                Message = "Test notification",
                CreatedAt = DateTime.Now,
                CreatedBy = "Test",
                IsRead = false
            };

            _context.Notifications.Add(notification);
            _context.SaveChanges();

            var retrieved = _context.Notifications.Find(notification.Id);
            Assert.NotNull(retrieved);
            Assert.Equal("Test notification", retrieved!.Message);
        }

        [Fact]
        public void Enrollment_NullGrade_IsAllowed()
        {
            TestHelpers.SeedCourses(_context);
            TestHelpers.SeedStudents(_context);
            var student = _context.Students.First();
            var course = _context.Courses.First();

            var enrollment = new Enrollment
            {
                StudentID = student.ID,
                CourseID = course.CourseID,
                Grade = null
            };

            _context.Enrollments.Add(enrollment);
            _context.SaveChanges();

            var retrieved = _context.Enrollments.First(e => e.StudentID == student.ID && e.CourseID == course.CourseID);
            Assert.Null(retrieved.Grade);
        }
    }
}

